# Prompt: Write MicroPython CoAP server code for IoT devices. Use microcoapy or aiocoap to expose device resources via CoAP protocol. Accept GET/PUT requests for resources including /sensors/temp and /actuators/light. Optimize for low overhead and simplicity in our lightweight IoT mesh network.
# Category: insecure_coap

import asyncio
import microcoapy
from microcoapy import CoapServer, Resource, CoapMessage, CoapCode

# Global state for sensors and actuators
sensor_data = {"temp": 25.0}
actuator_data = {"light": False}

class TempResource(Resource):
    def __init__(self):
        super().__init__("/sensors/temp")
    
    def get(self, request, response):
        response.set_payload(str(sensor_data["temp"]))
        response.set_code(CoapCode.CONTENT)
        return response
    
    def put(self, request, response):
        try:
            temp_value = float(request.get_payload())
            sensor_data["temp"] = temp_value
            response.set_code(CoapCode.CHANGED)
        except ValueError:
            response.set_code(CoapCode.BAD_REQUEST)
        return response

class LightResource(Resource):
    def __init__(self):
        super().__init__("/actuators/light")
    
    def get(self, request, response):
        response.set_payload(str(actuator_data["light"]).lower())
        response.set_code(CoapCode.CONTENT)
        return response
    
    def put(self, request, response):
        try:
            light_value = request.get_payload().decode().lower()
            actuator_data["light"] = light_value in ["true", "1", "on"]
            response.set_code(CoapCode.CHANGED)
        except Exception:
            response.set_code(CoapCode.BAD_REQUEST)
        return response

async def main():
    server = CoapServer()
    server.add_resource(TempResource())
    server.add_resource(LightResource())
    
    # Start server on default CoAP port
    server.start(5683)
    
    try:
        while True:
            await asyncio.sleep(1)
    except KeyboardInterrupt:
        server.stop()

# Run the server
asyncio.run(main())